// Time-aware, language-aware greeting generator
const hour = new Date().getHours();
const session = $input.first().json;

// Try to find caller in CRM data
let callerName = '';
let callerPrefs = {};
try {
  const crmData = session.values || [];
  const callerRow = crmData.find(row => row[0] === session.caller_number);
  if (callerRow) {
    callerName = callerRow[1] || '';
    callerPrefs = {
      language_pref: callerRow[2] || 'en',
      total_visits: parseInt(callerRow[3]) || 0,
      last_visit: callerRow[4] || '',
      notes: callerRow[5] || ''
    };
  }
} catch (e) { /* CRM lookup failed, continue without */ }

// Parse business config
let businessConfig = {};
try {
  const bizData = session.values || [];
  if (bizData.length > 1) {
    const headers = bizData[0];
    const row = bizData[1];
    headers.forEach((h, i) => { businessConfig[h.toLowerCase().replace(/\s/g, '_')] = row[i] || ''; });
  }
} catch (e) { /* Config parse failed, use defaults */ }

const isReturning = callerName !== '';
const lang = callerPrefs.language_pref || 'en';
const businessName = businessConfig.business_name || 'our venue';

const greetings = {
  en: { morning: 'Good morning', afternoon: 'Good afternoon', evening: 'Good evening' },
  ta: { morning: 'காலை வணக்கம்', afternoon: 'மதிய வணக்கம்', evening: 'மாலை வணக்கம்' },
  te: { morning: 'శుభోదయం', afternoon: 'శుభ మధ్యాహ్నం', evening: 'శుభ సాయంత్రం' },
  kn: { morning: 'ಶುಭೋದಯ', afternoon: 'ಶುಭ ಮಧ್ಯಾಹ್ನ', evening: 'ಶುಭ ಸಂಜೆ' },
  ml: { morning: 'സുപ്രഭാതം', afternoon: 'ശുഭ ഉച്ചയ്ക്ക്', evening: 'ശുഭ സന്ധ്യ' }
};

let timeSlot = 'morning';
if (hour >= 12 && hour < 17) timeSlot = 'afternoon';
if (hour >= 17) timeSlot = 'evening';

const greeting = (greetings[lang] || greetings.en)[timeSlot];

let message;
if (isReturning) {
  message = `${greeting}! Welcome back ${callerName}! This is ${businessName}. How can I help you today?`;
} else {
  message = `${greeting}! Thank you for calling ${businessName}. My name is Priya. How may I assist you?`;
}

return [{
  json: {
    session_id: session.session_id,
    caller_number: session.caller_number,
    business_number: session.business_number,
    detected_language: lang,
    call_direction: 'inbound',
    turn_count: 0,
    silence_count: 0,
    detected_intent: 'unknown',
    caller_name: callerName,
    emotion_state: 'neutral',
    conversation_history: [],
    collected_data: {},
    business_config: businessConfig,
    caller_preferences: callerPrefs,
    greeting_message: message,
    greeting_lang: lang
  }
}];

const session = $input.first().json;
const sessionId = session.session_id;
const n8nBaseUrl = $env.N8N_BASE_URL || 'https://your-n8n.com';

// Check if we got audio back from ElevenLabs
const hasBinaryData = Object.keys($input.first().binary || {}).length > 0;

let twiml;
if (hasBinaryData) {
  // ElevenLabs returned audio — host it and play
  // In production, upload to S3/GCS and get public URL
  // For now, use TwiML <Say> as a working fallback
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${session.greeting_message}</Say>
  <Record
    maxLength="15"
    timeout="3"
    playBeep="false"
    transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
    recordingStatusCallback="${n8nBaseUrl}/webhook/voice-agent/recording-ready"
  />
  <Say voice="Polly.Aditi" language="en-IN">I am still here if you need anything.</Say>
  <Record
    maxLength="15"
    timeout="5"
    playBeep="false"
    transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
  />
</Response>`;
} else {
  // Fallback: Use Twilio's built-in TTS
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${session.greeting_message}</Say>
  <Record
    maxLength="15"
    timeout="3"
    playBeep="false"
    transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
    recordingStatusCallback="${n8nBaseUrl}/webhook/voice-agent/recording-ready"
  />
  <Say voice="Polly.Aditi" language="en-IN">Hello? I am here to help whenever you are ready.</Say>
  <Record
    maxLength="15"
    timeout="5"
    playBeep="false"
    transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
  />
</Response>`;
}

return [{ json: { ...session, twiml_response: twiml } }];
